  "type": "DRAG_FILL",
  "data": {
    "challenges": [
      {
        "instruction": "Fill in the blanks using clues from the Historical Timeline of Khayan Township. Refer to the Learning Cards and Concept Breakdown for hints.",
        "codeTemplate": "Khayan Township's history is influenced by _____ cultures and significant events, including the establishment of _____ routes that facilitated trade.",
        "options": [
          "diverse",
          "ancient",
          "modern",
          "trade",
          "cultural",
          "military"
        ],
        "correctAnswer": "diverse,trade",
        "explanation": "Khayan Township's history is shaped by diverse cultures and significant events, including the establishment of trade routes."
      },
      {
        "instruction": "Complete the statement by filling in the blanks based on the Key Historical Milestones discussed earlier.",
        "codeTemplate": "One of the key historical milestones in Khayan Township was the _____ of trade routes, which led to increased _____ exchanges.",
        "options": [
          "establishment",
          "decline",
          "disruption",
          "cultural",
          "economic",
          "political"
        ],
        "correctAnswer": "establishment,cultural",
        "explanation": "The establishment of trade routes in Khayan Township led to increased cultural exchanges."
      }
    ]
  }
}
